-- 3.1 Introduction
INSERT INTO lessons (id, module_id, course_id, title, description, content_type, order_index, is_published, content_json)
VALUES ('lesson-overview-intro', 'mod-overview', 'smartwatch-course', 'Introduction', 'Introduction to the smartwatch project', 'text', 0, 1,
'{"sections":[{"title":"Introduction","content":"In this program you will design and implement a fully functioning smartwatch by combining low level driver development, embedded systems programming, and system-level integration.\n\nYou will work on the **LilyGo T-Watch 2020 V3**, a real commercial smartwatch platform, and write production-style firmware entirely in C and C++: the same languages used in industry for resource-constrained embedded systems.\n\n- **C** is used for low-level hardware control and communication\n- **C++** enables modular design, abstraction, and higher-level application logic\n\nThroughout the program you will build your system incrementally using provided training materials, reference implementations, and targeted code examples. These resources are designed to support you without removing the need for engineering decision making.\n\nIf you need help, email **support@shortcct.com** with your specific questions and a zip file including your project directory. Remember, virtual support is available for **3 months** after your product delivery date."}]}');

-- 3.2 Recommended Background
INSERT INTO lessons (id, module_id, course_id, title, description, content_type, order_index, is_published, content_json)
VALUES ('lesson-overview-background', 'mod-overview', 'smartwatch-course', 'Recommended Background', 'Prerequisites and recommended knowledge', 'text', 1, 1,
'{"sections":[{"title":"Recommended Background","content":"This project is designed for students who want hands-on embedded firmware experience. You do not need a lot of experience, but some foundational knowledge is expected.\n\n**Required**\n- Introductory programming experience in C or C++\n- Comfort with basic programming concepts such as functions, control flow, arrays, and structs\n\n**Helpful**\n- Introductory exposure to embedded systems\n- Introductory electronics knowledge\n\nIf you find that you are missing some of this background, reach out to us at **support@shortcct.com** and we can explore options to get you up to speed!"}]}');

