INSERT INTO lessons (id, module_id, course_id, title, description, content_type, order_index, is_published, content_json)
VALUES ('lesson-overview-industry', 'mod-overview', 'smartwatch-course', 'Industry Alignment', 'How the project aligns with industry skills', 'text', 2, 1,
